const survives = (liveNeighbors: number): boolean =>
  liveNeighbors === 2 || liveNeighbors === 3;

const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveCells = new Set(cells.map(cellKey));

  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter((n) => liveCells.has(cellKey(n))).length;

  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    for (const candidate of [cell, ...neighborsOf(cell)]) {
      candidates.set(cellKey(candidate), candidate);
    }
  }

  const result: Cell[] = [];
  for (const [key, cell] of candidates) {
    const liveNeighbors = countLiveNeighbors(cell);
    if (liveCells.has(key) ? survives(liveNeighbors) : isBorn(liveNeighbors)) {
      result.push(cell);
    }
  }
  return result;
};

